  void _setupPushNotifications() async {
    NotificationSettings settings = await _firebaseMessaging.requestPermission(
      alert: true,
      badge: true,
      sound: true,
    );

    if (settings.authorizationStatus == AuthorizationStatus.authorized) {
      String? token = await _firebaseMessaging.getToken();
      print('FCM Token: $token');

      FirebaseMessaging.onMessage.listen((RemoteMessage message) {
        _sendMessageToWeb('onNotificationReceived', {
          'title': message.notification?.title ?? '',
          'body': message.notification?.body ?? '',
          'data': message.data,
        });
      });

      FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
        _sendMessageToWeb('onNotificationOpened', {
          'title': message.notification?.title ?? '',
          'body': message.notification?.body ?? '',
          'data': message.data,
        });
      });
    }
  }

  void _sendMessageToWeb(String event, Map<String, dynamic> data) {
    final jsonData = jsonEncode(data);
    _controller.runJavaScript(
      "window.dispatchEvent(new CustomEvent('$event', { detail: $jsonData }));",
    );
  }

  Future<void> _openCamera() async {
    try {
      final XFile? photo = await _imagePicker.pickImage(
        source: ImageSource.camera,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (photo != null) {
        final bytes = await photo.readAsBytes();
        final base64Image = base64Encode(bytes);
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('onCameraResult', { detail: { success: true, image: 'data:image/jpeg;base64,$base64Image', path: '${photo.path}' } }));",
        );
      } else {
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('onCameraResult', { detail: { success: false, error: 'User cancelled' } }));",
        );
      }
    } catch (e) {
      _controller.runJavaScript(
        "window.dispatchEvent(new CustomEvent('onCameraResult', { detail: { success: false, error: '${e.toString()}' } }));",
      );
    }
  }

  Future<void> _pickImage() async {
    try {
      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.gallery,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('onImagePicked', { detail: { success: true, image: 'data:image/jpeg;base64,$base64Image', path: '${image.path}' } }));",
        );
      } else {
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('onImagePicked', { detail: { success: false, error: 'User cancelled' } }));",
        );
      }
    } catch (e) {
      _controller.runJavaScript(
